<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Response { function approve(string $message, mixed $data = [], array $expressions = [], array $placeholders = []): void { $this->resolve( (TAPMEPPE_MODE_COLOR ? Logger::colorise('[SUCCESS]', 0, 32) . $message : "[SUCCESS] $message"), $data, $expressions, $placeholders, ); } function confirm(string $message, mixed $data = [], array $expressions = [], array $placeholders = []): void { $this->approve($message, $data, $expressions, $placeholders); exit(0); } function fail(Reason $reason, mixed $data = [], array $expressions = [], array $placeholders = []): void { $this->resolve( (TAPMEPPE_MODE_COLOR ? Logger::colorise('[ERROR]', 0, 31) . $reason->toString() : "[ERROR] {$reason->toString()}"), $data, $expressions, $placeholders, ); } function inform(string $message, mixed $data = [], array $expressions = [], array $placeholders = []): void { $this->resolve( (TAPMEPPE_MODE_COLOR ? Logger::colorise('[INFO]', 0, 36) . $message : "[INFO] $message"), $data, $expressions, $placeholders, ); } function interupt(...$data): void { if (TAPMEPPE_MODE_DEVELOPMENT) $this->reject(Reason::interupted, $data); } function reject(Reason $reason, mixed $data = [], array $expressions = [], array $placeholders = []): void { $this->fail($reason, $data, $expressions, $placeholders); exit(1); } function renounce(Reason $reason, mixed $data = [], array $expressions = [], array $placeholders = []): void { Utilities::report(compact('reason', 'data')); $this->reject($reason, $data, $expressions, $placeholders); } private function resolve(string $message, mixed $data = [], array $expressions = [], array $placeholders = []): void { echo "$message\n"; if ($data) echo Logger::stringifyArray($data, $expressions, $placeholders) . PHP_EOL; echo "➖➖➖\n"; } } 